import React, { useEffect, useState } from 'react';

const App = () => {
  const [accessToken, setAccessToken] = useState(null);

  useEffect(() => {
    const hash = window.location.hash;
    if (hash) {
      const token = new URLSearchParams(hash.replace('#', '?')).get('access_token');
      if (token) {
        setAccessToken(token);
        window.location.hash = ''; // Clear the hash
      }
    }
  }, []);

  const handleLogin = () => {
    const clientId = 'YOUR_CLIENT_ID';
    const redirectUri = 'YOUR_REDIRECT_URI';
    const authUrl = `https://authorization-server.com/auth?response_type=token&client_id=${clientId}&redirect_uri=${redirectUri}`;
    window.location.href = authUrl;
  };

  return (
    <div>
      <h1>OAuth 2.0 Implicit Flow Example</h1>
      {accessToken ? (
        <div>
          <h2>Access Token:</h2>
          <p>{accessToken}</p>
        </div>
      ) : (
        <button onClick={handleLogin}>Login with OAuth</button>
      )}
    </div>
  );
};

export default App;